public int lengthOfLastWord(String s) {
    int length = 0;
    int tail = s.length() - 1;
    while (tail >= 0 && s.charAt(tail) == ' ') tail--;
    while (tail >= 0 && s.charAt(tail) != ' ') {
        length++;
        tail--;
    }
    return length;
}
